function parseMarkdown(md) {
  const lines = md.split('\n');
  const titleLine = lines.find(l => l.startsWith('# '));
  const title = titleLine ? titleLine.replace(/^# /, '') : 'Untitled';
  const titleIdx = lines.indexOf(titleLine);
  const descLines = [];
  for (let i = (titleIdx >= 0 ? titleIdx + 1 : 0); i < lines.length; i++) {
    if (lines[i].startsWith('## ')) break;
    descLines.push(lines[i]);
  }
  const description = descLines.join(' ').replace(/\s+/g, ' ').trim();
  function getSection(heading) {
    const start = lines.findIndex(l => l.startsWith('## ' + heading));
    if (start === -1) return [];
    const out = [];
    for (let i = start + 1; i < lines.length; i++) {
      if (lines[i].startsWith('## ')) break;
      if (lines[i].trim()) out.push(lines[i]);
    }
    return out;
  }
  function getField(heading) { const s = getSection(heading); return s.length ? s[0].trim() : ''; }
  const criteria = getSection('Acceptance Criteria').filter(l => l.startsWith('- ')).map(l => l.replace(/^- /, ''));
  const priority = getField('Priority') || ($env.JIRA_DEFAULT_PRIORITY || 'Medium');
  const estimate = getField('Estimate');
  const component = getField('Component');
  const labelsStr = getField('Labels');
  const labels = ['ai-generated'];
  if (labelsStr) labels.push(...labelsStr.split(',').map(l => l.trim()).filter(Boolean));
  if (component) labels.push(component);
  return { title, description, criteria, priority, estimate, component, labels };
}

function buildJiraFields(parsed, issueType, parentKey) {
  const content = [];
  if (parsed.description) content.push({ type: 'paragraph', content: [{ type: 'text', text: parsed.description }] });
  if (parsed.criteria.length > 0) {
    content.push({ type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Acceptance Criteria' }] });
    content.push({ type: 'bulletList', content: parsed.criteria.map(c => ({ type: 'listItem', content: [{ type: 'paragraph', content: [{ type: 'text', text: c }] }] })) });
  }
  const fields = {
    summary: parsed.title,
    description: { type: 'doc', version: 1, content },
    priority: { name: parsed.priority },
    labels: parsed.labels
  };
  if (parentKey) fields.parent = { key: parentKey };
  return fields;
}

function extractKey(input) {
  if (!input) return '';
  const browseMatch = input.match(/\/browse\/([A-Z]+-\d+)/);
  if (browseMatch) return browseMatch[1];
  if (input.match(/^[A-Z]+-\d+$/)) return input;
  return input.trim();
}

const body = $input.first().json.body;
const epicMarkdown = body.epicMarkdown || '';
const taskMarkdowns = body.taskMarkdowns || [];
const epicKey = extractKey(body.epicKey || '');
const taskKeys = (body.taskKeys || []).map(k => extractKey(k));

const epicParsed = parseMarkdown(epicMarkdown);
const epicIssueType = $env.JIRA_EPIC_ISSUE_TYPE || 'Epic';

// For create: include project + issuetype. For update: only updatable fields.
let epicApiBody, epicMethod, epicUrl;
if (epicKey) {
  epicMethod = 'PUT';
  epicUrl = $env.JIRA_BASE_URL + '/rest/api/3/issue/' + epicKey;
  epicApiBody = { fields: buildJiraFields(epicParsed, epicIssueType) };
} else {
  epicMethod = 'POST';
  epicUrl = $env.JIRA_BASE_URL + '/rest/api/3/issue';
  const fields = buildJiraFields(epicParsed, epicIssueType);
  fields.project = { key: $env.JIRA_PROJECT_KEY };
  fields.issuetype = { name: epicIssueType };
  epicApiBody = { fields };
}

return [{ json: { epicApiBody, epicMethod, epicUrl, epicKey, epicTitle: epicParsed.title, taskMarkdowns, taskKeys, isUpdate: !!epicKey } }];

